import { Component } from "react";
import './Switch.css'

const styles = {
    off: {
        justifyContent: 'flex-start'
    },
    on: {
        justifyContent: 'flex-end'
    }
}

class Switch extends Component {
    render(){
        const { cambiarTema, temaOscuro } = this.props
        var opcion = '';
        if (temaOscuro){ 
            opcion = '-dark'
        }
        else {
            opcion = ''
        }
        return (
            <div style={styles.off} className={'contenedor-switch' + opcion}>
                <button onClick={cambiarTema} className={'switch' + opcion}>{opcion}</button>
            </div>
        )
    }
}

export default Switch
